from odoo import models, fields, api

class SaleOrder(models.Model):
    _inherit = 'sale.order'

    total_weight = fields.Float(compute='_compute_total_weight', store=True)

    @api.depends('order_line.product_uom_qty', 'order_line.product_id.weight')
    def _compute_total_weight(self):
        for order in self:
            order.total_weight = sum(line.product_uom_qty * line.product_id.weight for line in order.order_line)
store=True stores the computed value in the database so it can be searched and used in reports.

